        self.limit = limit
        self._cache = {}

    def setNum(self):
        total = len(self.lst)
        base = total // self.limit
        rem = total % self.limit
        return (base, rem)

    def get(self, index):
        if not isinstance(index, int):
            raise TypeError("index must be an integer")
