        return key

    @staticmethod
    def _to_camel_case(key):
        if not isinstance(key, str):
            return key
        res_chars = []
        upper_next = False
        for ch in key:
            if ch == '_':
                upper_next = True
                continue
            if upper_next:
                res_chars.append(ch.upper())
                upper_next = False
            else:
                res_chars.append(ch)
        return ''.join(res_chars)

