        return key

    @staticmethod
    def _to_camel_case(key):
        if not isinstance(key, str):
            return key
        # use title on each segment then lowercase first letter of result
        parts = [p for p in key.split('_')]
        if not parts:
            return ''
        # preserve empty segments by treating them as empty strings
