        result = (amt * rate_to) / rate_from
        return float(result)

    def get_supported_currencies(self):
        return list(self.rates.keys())

    def add_currency_rate(self, currency, rate):
        if currency in self.rates:
            return False
        try:
            r = Decimal(str(rate))
