                out.append(chr((ord(ch) - base - k) % 26 + base))
            else:
                out.append(ch)
        return ''.join(out)

    def rail_fence_decipher(self, encrypted_text, rails):
        if rails is None or rails <= 1:
            return encrypted_text
        n = len(encrypted_text)
        pattern = []
        r = 0
        dir = 1
        for _ in range(n):
            pattern.append(r)
            if r == 0:
                dir = 1
            elif r == rails - 1:
                dir = -1
            r += dir
        counts = [0]*rails
        for p in pattern:
            counts[p] += 1
        parts = []
        idx = 0
        for c in counts:
            parts.append(list(encrypted_text[idx:idx+c]))
            idx += c
        pointers = [0]*rails
        res = []
        for p in pattern:
            res.append(parts[p][pointers[p]])
            pointers[p] += 1
        return ''.join(res)

