        n = len(d)
        half = n // 2
        if n % 2:
            return float(d[half])
        return (d[half - 1] + d[half]) / 2.0

    @staticmethod
    def mode(data):
        if not data:
            return []
        cnt = Counter(data)
        maxfreq = max(cnt.values())
        modes = [k for k, v in cnt.items() if v == maxfreq]
        try:
            return sorted(modes)
        except TypeError:
            return modes

