            if '=' in part:
                k, v = part.split('=', 1)
                k = unquote_plus(k)
                v = unquote_plus(v)
            else:
                k = unquote_plus(part)
                v = ''
            # choose last occurrence
            params[k] = v
        return params

    def get_fragment(self):
        return self._fragment

