import urllib.parse

class UrlPath:
    """
    The  class is a utility for encapsulating and manipulating the path component of a URL, including adding nodes, parsing path strings, and building path strings with optional encoding.
    """

    def __init__(self):
        """
        Initializes the UrlPath object with an empty list of segments and a flag indicating the presence of an end tag.
        """
        self.segments = []
        self.with_end_tag = False

    def add(self, segment):
        """
        Adds a segment to the list of segments in the UrlPath.
        This variant treats '.' and '..' specially: '.' ignored, '..' pops a previous segment.
        """
        if segment is None:
            return
        s = str(segment)
        if s == '':
            self.with_end_tag = True
            return
        parts = [p for p in s.split('/') if p != '']
        for p in parts:
            if p == '.':
                continue
            if p == '..':
                if self.segments:
                    self.segments.pop()
                continue
            self.segments.append(p)
        self.with_end_tag = False

    def parse(self, path, charset):
        """
        Parses a given path string and populates the list of segments in the UrlPath.
        This variant normalizes '.' and '..' while decoding percent-encodings using charset.
        """
        self.segments = []
        self.with_end_tag = False
        if path is None:
            return
        try:
            path_only = urllib.parse.urlsplit(path).path or ''
        except Exception:
            path_only = path or ''
        if path_only.endswith('/'):
            self.with_end_tag = True
        fixed = self.fix_path(path_only)
        if fixed == '':
            return
        parts = [p for p in fixed.split('/') if p != '']
        for p in parts:
            # decode using bytes decode to ensure charset respected
            try:
                raw_bytes = urllib.parse.unquote_to_bytes(p)
                decoded = raw_bytes.decode(charset, errors='replace')
            except Exception:
                decoded = urllib.parse.unquote(p)
            if decoded == '.':
                continue
            if decoded == '..':
                if self.segments:
                    self.segments.pop()
                continue
            self.segments.append(decoded)

    @staticmethod
    def fix_path(path):
        """
        Fixes the given path string by removing leading and trailing slashes.
        """
        if path is None:
            return ''
        try:
            p = urllib.parse.urlsplit(path).path
            if p is None:
                p = path
        except Exception:
            p = path
        # strip leading/trailing slashes and collapse repeated ones into single separators
        # simple collapse: replace '//' with '/' until none remain
        while '//' in p:
            p = p.replace('//', '/')
        return p.strip('/')

