                            base = tok[:-len(end)] + rep
                            if base in self.numwords:
                                conv = self.numwords[base]
                                break
                if conv:
                    scale, inc = conv
                else:
                    raise ValueError("Invalid token: {}".format(tok))
            if scale > 1:
                if current == 0:
                    current = 1
                current *= scale
                if scale > 100:
                    total += current
                    current = 0
            else:
                current += inc
            i += 1
        return total + current

