            raise ValueError("Input must be string")
        tokens = self._split(textnum)
        if not tokens:
            return "0"
        negative = False
        if tokens[0] in ('minus', 'negative'):
            negative = True
            tokens = tokens[1:]
        result = self._parse_chunk(tokens)
        if negative:
            result = -result
        return str(result)

    def is_valid_input(self, textnum):
        if not isinstance(textnum, str):
            return False
        if '-' in textnum:
            return False
        tokens = self._split(textnum)
        if not tokens:
            return False
        for tok in tokens:
