        if self.minesweeper_map[x][y] == 'X':
            self.player_map[x][y] = 'X'
            return False
        # iterative DFS stack
        stack = [(x, y)]
        newly = 0
        while stack:
            i, j = stack.pop()
            if not (0 <= i < self.n and 0 <= j < self.n):
                continue
            if self.player_map[i][j] != '-':
