            raise TypeError("decimal_num must be int")
        def rec(n):
            if n < 2:
                return '1' if n == 1 else '0'
            q, r = divmod(n, 2)
            prefix = rec(q)
            if prefix == '0':
                prefix = ''
            return prefix + str(r)
