                    result.append(chr(code))
                else:
                    result.append(m.group(0))
            except Exception:
                result.append(m.group(0))
            last = m.end()
        result.append(string[last:])
        return ''.join(result)

    @staticmethod
    def is_hex_char(char):
        if not isinstance(char, str) or len(char) != 1:
            return False
        return char in "0123456789abcdefABCDEF"

