        except re.error:
            return False

    def extract_email(self, text):
        pat = self.generate_email_pattern()
        try:
            # Use IGNORECASE to be forgiving on TLD case
            found = re.findall(pat, text, flags=re.IGNORECASE)
            # return unique preserving order
            seen = set()
            out = []
            for e in found:
